	@Test
	void shouldCancelOnlyOneHeavyQueryPerCooldownWindow() {
		Fixture fixture = new Fixture();
		QueryCircuitBreaker breaker = fixture.breaker(configuration(true, 100, 200, 300, 400, 300, 200, 25, 10, 1000,
				7), 1000);
		QueryCircuitBreakerHandle firstHeavy = breaker.register(QueryCircuitBreakerHandle.Source.SERVER, "repo",
				"first");
		QueryCircuitBreakerHandle secondHeavy = breaker.register(QueryCircuitBreakerHandle.Source.SERVER, "repo",
				"second");

		fixture.clock.set(10);
		breaker.markHeavy(firstHeavy, "GROUP_BY");
		fixture.clock.set(20);
		breaker.markHeavy(secondHeavy, "ORDER_BY");

		fixture.freeMemoryMb.set(150);

		QueryCircuitBreakerHandle firstAdmission = breaker.register(QueryCircuitBreakerHandle.Source.SERVER, "repo",
				"admission-1");
		assertThrows(QueryCircuitBreaker.CircuitBreakerException.class, () -> breaker.beforeExecution(firstAdmission));
		assertTrue(secondHeavy.isCancelRequested());
		assertFalse(firstHeavy.isCancelRequested());
		assertEquals(1, breaker.snapshotStatus().getCancelCount());

		QueryCircuitBreakerHandle secondAdmission = breaker.register(QueryCircuitBreakerHandle.Source.SERVER, "repo",
				"admission-2");
		assertThrows(QueryCircuitBreaker.CircuitBreakerException.class, () -> breaker.beforeExecution(secondAdmission));
		assertFalse(firstHeavy.isCancelRequested());
		assertEquals(1, breaker.snapshotStatus().getCancelCount());

		fixture.clock.addAndGet(1001);
		QueryCircuitBreakerHandle thirdAdmission = breaker.register(QueryCircuitBreakerHandle.Source.SERVER, "repo",
				"admission-3");
		assertThrows(QueryCircuitBreaker.CircuitBreakerException.class, () -> breaker.beforeExecution(thirdAdmission));
		assertTrue(firstHeavy.isCancelRequested());
		assertEquals(2, breaker.snapshotStatus().getCancelCount());

		breaker.complete(firstHeavy);
		breaker.complete(secondHeavy);
		breaker.complete(firstAdmission);
		breaker.complete(secondAdmission);
		breaker.complete(thirdAdmission);
	}

